object Solution {
  /**
    * Calculates the smallest stable index i such that max(nums[0..i]) - min(nums[i..n-1]) <= k.
    *
    * @param nums The input array of integers.
    * @param k The threshold value.
    * @return The smallest stable index, or -1 if none exists.
    */
  def nums(nums: Array[Long]): Long = {
    val n = nums.length

    if (n == 0) return -1L

    // Precompute prefix maximums: prefixMax[i] = max(nums[0..i])
    val prefixMax = Array.ofDim[Long](n)
    prefixMax(0) = nums(0)
    for (i <- 1 until n) {
      prefixMax(i) = math.max(prefixMax(i - 1), nums(i))
    }

    // Precompute suffix minimums: suffixMin[i] = min(nums[i..n-1])
    val suffixMin = Array.ofDim[Long](n)
    suffixMin(n - 1) = nums(n - 1)
    for (i <- n - 2 until -1) {
      suffixMin(i) = math.min(suffixMin(i + 1), nums(i))
    }

    // Iterate through all indices i and check the stability condition
    for (i <- 0 until n) {
      val currentMax = prefixMax(i)
      val currentMin = suffixMin(i)
      val unstableValue = currentMax - currentMin

      if (unstableValue <= k) {
        return i.toLong
      }
    }

    // If no stable index is found
    -1L
  }
}
